const input = $input.first().json;
const query = input.query || input || {};
const domain = String(process.env.MAKESHOP_DOMAIN || 'foreverlove.co.kr').trim();
const shopkey = String(process.env.MAKESHOP_SHOPKEY || '').trim();
const licensekey = String(process.env.MAKESHOP_LICENSEKEY || '').trim();
if (!shopkey || !licensekey) {
  throw new Error('MAKESHOP_SHOPKEY / MAKESHOP_LICENSEKEY 이 설정되지 않았습니다.');
}
function getParts(date) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Asia/Seoul',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hourCycle: 'h23',
  }).formatToParts(date);
  return Object.fromEntries(parts.filter((part) => part.type !== 'literal').map((part) => [part.type, part.value]));
}
function formatDate(date) {
  const p = getParts(date);
  return `${p.year}-${p.month}-${p.day}`;
}
function formatDateTime(date, tail) {
  return `${formatDate(date)} ${tail}`;
}
const now = new Date();
const inquiryFrom = String(query.inquiryFrom || formatDateTime(new Date(now.getTime() - 6 * 24 * 60 * 60 * 1000), '00:00:00')).trim();
const inquiryTo = String(query.inquiryTo || formatDateTime(now, '23:59:59')).trim();
const reviewFrom = String(query.reviewFrom || formatDate(new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000))).trim();
const reviewTo = String(query.reviewTo || formatDate(now)).trim();
const page = String(query.page || '1').trim();
const limit = String(query.limit || '50').trim();
const memberType = String(query.memberType || 'MEMBER').trim();
const onlyPending = String(query.onlyPending || 'true').trim().toLowerCase() !== 'false';
const baseUrl = `https://${domain}`;
const crmQuery = new URLSearchParams({
  mode: 'search',
  type: 'crm_board',
  InquiryTimeFrom: inquiryFrom,
  InquiryTimeTo: inquiryTo,
  is_member: memberType,
  page,
  limit,
}).toString();
const reviewQuery = new URLSearchParams({
  mode: 'search',
  type: 'review',
  InquiryTimeFrom: reviewFrom,
  InquiryTimeTo: reviewTo,
  page,
  limit,
}).toString();
return [{ json: {
  base_url: baseUrl,
  crm_url: `${baseUrl}/list/open_api.html?${crmQuery}`,
  review_url: `${baseUrl}/list/open_api.html?${reviewQuery}`,
  shopkey,
  licensekey,
  only_pending: onlyPending,
  inquiry_from: inquiryFrom,
  inquiry_to: inquiryTo,
  review_from: reviewFrom,
  review_to: reviewTo,
  adapter_version: 'makeshop-adapter-v1',
} }];

function extractRecords(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && Array.isArray(payload.list)) return payload.list;
  if (payload && payload.data && Array.isArray(payload.data.list)) return payload.data.list;
  return [];
}
function toIsoKst(value) {
  const raw = String(value || '').trim();
  if (!raw) return new Date().toISOString();
  const normalized = raw.includes('T') ? raw : raw.replace(' ', 'T') + '+09:00';
  const date = new Date(normalized);
  return Number.isNaN(date.getTime()) ? new Date().toISOString() : date.toISOString();
}
function maskName(value) {
  const text = String(value || '고객').trim();
  if (text.length <= 1) return text;
  if (text.length === 2) return `${text[0]}*`;
  return `${text[0]}${'*'.repeat(Math.max(1, text.length - 2))}${text[text.length - 1]}`;
}
function buildInquiryId(row, index) {
  const seed = `${row.date || ''}_${row.userid || row.phone || row.subject || index}`.replace(/[^0-9A-Za-z가-힣_-]/g, '');
  return `crm_${seed || index}`;
}
const request = $('요청 파라미터 정리').first().json;
const crmPayload = $('메이크샵 문의 조회').first().json;
const reviewPayload = $('메이크샵 리뷰 조회').first().json;
const crmItems = extractRecords(crmPayload).map((row, index) => ({
  id: buildInquiryId(row, index),
  orderId: '',
  productId: '',
  productName: '',
  customerName: maskName(row.hname || row.userid || '고객'),
  subject: String(row.subject || '메이크샵 문의'),
  body: String(row.content || ''),
  status: String(row.reply_yn || '').toUpperCase() === 'Y' ? 'ANSWERED' : 'OPEN',
  receivedAt: toIsoKst(row.date),
  url: 'https://admin.makeshop.co.kr/',
  sourceKind: 'crm_board',
  answered: String(row.reply_yn || '').toUpperCase() === 'Y',
  answerPreview: String(row.reply_content || ''),
  rawPayloadSummary: `crm_board:${row.board_name || ''}:${row.date || ''}`,
  tags: ['메이크샵', '문의'],
  ...row,
}));
const reviewItems = extractRecords(reviewPayload).map((row, index) => ({
  id: String(row.uid || `review_${index}`),
  orderId: '',
  productId: '',
  productName: '',
  customerName: maskName(row.hname || row.userid || '고객'),
  subject: String(row.subject || '메이크샵 후기'),
  body: String(row.content || ''),
  status: String(row.reply_content || '').trim() ? 'ANSWERED' : 'OPEN',
  receivedAt: toIsoKst(row.date),
  url: 'https://admin.makeshop.co.kr/',
  sourceKind: 'review',
  itemType: 'review',
  answered: Boolean(String(row.reply_content || '').trim()),
  answerPreview: String(row.reply_content || ''),
  rawPayloadSummary: `review:${row.uid || ''}:${row.date || ''}`,
  tags: ['메이크샵', '리뷰'],
  ...row,
}));
let items = [...crmItems, ...reviewItems];
if (request.only_pending) {
  items = items.filter((row) => row.status === 'OPEN');
}
items.sort((a, b) => new Date(b.receivedAt).getTime() - new Date(a.receivedAt).getTime());
return [{ json: {
  items,
  meta: {
    adapter: 'makeshop-adapter-v1',
    onlyPending: request.only_pending,
    crmCount: crmItems.length,
    reviewCount: reviewItems.length,
    totalCount: items.length,
    inquiryFrom: request.inquiry_from,
    inquiryTo: request.inquiry_to,
    reviewFrom: request.review_from,
    reviewTo: request.review_to,
  }
} }];
